external_knowledge:
; A group discussion session is considered attended if the student's attendance status is marked as 'attended' in the attendance table; 
; The attendance status is 'Perfect Attendance' if the student attended all sessions and 'Partial Attendance' otherwise; 
; The participation level is 'Active Participant' if the student attended at least two sessions and 'Less Active' otherwise.

sql:
SELECT COUNT(DISTINCT student_id) AS total_students_attended
FROM attendance
WHERE attended = 1;

external_knowledge:
; The 'percentage of excellent performance' is calculated as (excellent performances / total attendees) * 100%; 
; 'Excellent performance' is assumed to be an indicator of outstanding performance, where students have performed exceptionally well; 
; 'Sessions' refer to the group discussion sessions with a specific time slot.

sql:
SELECT AVG(student_count) AS overall_average_students
FROM (
  SELECT session_id, COUNT(student_id) AS student_count
  FROM attendance
  GROUP BY session_id
) AS session_counts;
